#include <bits/stdc++.h>
#define ll long long
using namespace std;

const int N=1e5+5;

struct Item{
    int w,a,b;
}s[N];

struct Node{
    int id,val;
}d[N],edge[N];

struct Fa{
    int fa;
    ll sum;
    int siz,mn;
}f[N];

bool operator<(Item x,Item y){
    return x.w<y.w;
}

bool operator<(Node x,Node y){
    return x.val<y.val;
}

ll cal(Fa x){
    return x.sum+x.siz%2*x.mn;
}

int father(int x){
    return f[x].fa==x?x:f[x].fa=father(f[x].fa);
}

int n,q;

std::vector<long long> calculate_costs(
    std::vector<int> W, std::vector<int> A, 
    std::vector<int> B, std::vector<int> E){
    vector<ll> ans;
    n=W.size(),q=E.size();
    ll sum=0;
    for(int i=1;i<=n;i++)
        s[i]={W[i-1],A[i-1],B[i-1]};
    sort(s+1,s+n+1);
    for(int i=1;i<=q;i++)
        d[i]={i-1,E[i-1]},ans.push_back(0);
    sort(d+1,d+q+1);
    for(int i=1;i<n;i++)
        edge[i]={i,s[i+1].w-s[i].w};
    sort(edge+1,edge+n);
    for(int i=1;i<=n;i++)
        sum+=s[i].a,f[i]={i,s[i].b,1,s[i].a-s[i].b};
    for(int i=1,j=1;i<=q;i++){
        while(j<n && edge[j].val<=d[i].val){
            int x=father(edge[j].id),y=father(edge[j].id+1);
            sum-=cal(f[x])+cal(f[y]);
            f[y].fa=x,f[x].sum+=f[y].sum,f[x].siz+=f[y].siz;
            f[x].mn=min(f[x].mn,f[y].mn);
            sum+=cal(f[x]),j++;
        }
        ans[d[i].id]=sum;
    }
    return ans;
}
